# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
import os
from typing import Dict, List, Any

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    # Database connection parameters
    db_config = {
        'host': os.environ['DB_HOST'],
        'user': os.environ['DB_USER'],
        'password': os.environ['DB_PASSWORD'],
        'database': os.environ['DB_NAME'],
        'port': int(os.environ.get('DB_PORT', 3306))
    }
    
    # Extract search parameters from event
    query_params = event.get('queryStringParameters', {})
    
    # Build dynamic SQL query
    sql_query = "SELECT * FROM products WHERE 1=1"
    params = []
    
    # Add filters based on query parameters
    if query_params.get('name'):
        sql_query += " AND name LIKE %s"
        params.append(f"%{query_params['name']}%")
        
    if query_params.get('category'):
        sql_query += " AND category = %s"
        params.append(query_params['category'])
        
    if query_params.get('min_price'):
        sql_query += " AND price >= %s"
        params.append(float(query_params['min_price']))
        
    if query_params.get('max_price'):
        sql_query += " AND price <= %s"
        params.append(float(query_params['max_price']))
        
    if query_params.get('brand'):
        sql_query += " AND brand = %s"
        params.append(query_params['brand'])
    
    # Add sorting and pagination
    sort_by = query_params.get('sort_by', 'name')
    order = query_params.get('order', 'ASC')
    
    sql_query += f" ORDER BY {sort_by} {order}"
    
    page = int(query_params.get('page', 1))
    page_size = int(query_params.get('page_size', 10))
    offset = (page - 1) * page_size
    sql_query += f" LIMIT {page_size} OFFSET {offset}"
    
    try:
        # Connect to database
        connection = pymysql.connect(**db_config)
        
        with connection.cursor(pymysql.cursors.DictCursor) as cursor:
            cursor.execute(sql_query, params)
            results = cursor.fetchall()
            
        connection.close()
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'products': results,
                'page': page,
                'page_size': page_size,
                'total': len(results)
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'error': str(e)
            })
        }